  ('aboriginal-6f0ba476-moex-00632', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於遺產效力之敘述，何者錯誤？', '["民法第1150條所稱遺產管理之費用，具有共益之性質", "民法第1150條所稱遺產管理之費用，具有個別利益之性質", "遺產未分割前，得由繼承人互推一人管理之", "繼承人有數人時，在分割遺產前，各繼承人對於遺產全部為公同共有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00633', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲有子女乙丙丁戊四人。丙有子女丙1丙2二人。戊有子女戊1戊2戊3三人。乙丙一同出遊遇 難，甲聽聞噩耗悲痛猝逝，甲有遺產新臺幣（下同）3600萬元。戊發現甲所留下遺囑中指定乙繼 承其中半數，戊動手塗改，隨即被丁發現。下列敘述，何者正確？', '["丁得繼承900萬元", "戊得繼承1800萬元", "戊2得繼承600萬元", "丙2得繼承600萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
