  ('aboriginal-6f0ba476-moex-00639', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '乙為甲公司之受僱司機，僱傭契約約明乙執行開車職務侵害他人者，概由乙自行負侵權行為責任。 某日，乙開車運送途中不小心傷及路人丙。下列敘述，何者正確？', '["甲不必對丙負責", "應僅由乙對丙負責", "甲與乙對丙應連帶負責", "甲、乙應各別對丙負責，但不負連帶責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
